@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>
    Notifications
    <span class="badge bg-primary">@_notifications.Count</span>
</h3>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <small class="text-muted ms-2">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR — these appear in the first HTML render
        _notifications = NotificationService.GetNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is interactive (not during static SSR).
            // Start polling now that we have a live circuit.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken).ConfigureAwait(false);

            // Simulate a new notification arriving on the server side
            NotificationService.SimulateNewNotification();

            var newItems = NotificationService.GetNotificationsSince(lastId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                lastId = newItems.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

